// dstLocal: 存放Sinh计算结果的Tensor
// srcLocal: 存放Sinh计算输入的Tensor
// sharedTmpBuffer: 存放Sinh计算过程中临时缓存的Tensor

// 接口框架申请临时空间，全部参与计算
AscendC::Sinh(dstLocal, srcLocal);
// 接口框架申请临时空间，部分参与计算, 需要参与计算的元素个数为512
AscendC::Sinh(dstLocal, srcLocal, 512);

// 通过sharedTmpBuffer入参传入临时空间，全部参与计算
AscendC::Sinh(dstLocal, srcLocal, sharedTmpBuffer);
// 通过sharedTmpBuffer入参传入临时空间，部分参与计算, 需要参与计算的元素个数为512
AscendC::Sinh(dstLocal, srcLocal, sharedTmpBuffer, 512);
